def main():
    path = DATA_DIR / "best_of.json"
    data = json.loads(path.read_text())
    existing_slugs = {r["slug"] for r in data["roundups"]}

    added = 0
    skipped = 0
    for roundup in NEW_ROUNDUPS:
        if roundup["slug"] in existing_slugs:
            print(f"  SKIP (exists): {roundup['slug']}")
            skipped += 1
            continue
        data["roundups"].append(roundup)
        existing_slugs.add(roundup["slug"])
        added += 1
        print(f"  ADD: {roundup['slug']}")

    path.write_text(json.dumps(data, indent=2, ensure_ascii=False))
    print(f"\nDone: {added} added, {skipped} skipped. Total: {len(data['roundups'])} roundups.")


if __name__ == "__main__":
    main()
